args.sparql:
SELECT ?club WHERE {
  wd:Q10520 p:P54 ?membership .
  ?membership ps:P54 ?club .
  ?membership pq:P582 ?endTime .
  FILTER(YEAR(?endTime) = 2007)
}

SELECT ?club WHERE {
  wd:Q10520 p:P54 ?membership .
  ?membership ps:P54 ?club .
  ?membership pq:P582/wdtn:P582 ?endTime .
  FILTER(YEAR(?endTime) = 2007)
}

SELECT ?club ?endTime WHERE {
  wd:Q10520 p:P54 ?membership .
  ?membership ps:P54 ?club .
  ?membership pq:P582 ?endTime .
  FILTER regex(str(?endTime), "2007")
}
